import React, { useEffect, useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import authService from '../../services/authService';

const ROLE_LABELS = {
  PATIENT: 'Patient',
  DOCTOR: 'Doctor',
  HOSPITAL_ADMIN: 'Hospital Admin',
  SUPER_ADMIN: 'Super Admin',
};

const ROLE_WELCOME = {
  PATIENT: 'Manage your health journey — book appointments, view records, and consult doctors.',
  DOCTOR: 'Manage your schedule, review patient cases, and write prescriptions.',
  HOSPITAL_ADMIN: 'Oversee hospital operations, manage doctors, and review appointments.',
  SUPER_ADMIN: 'Full platform control — manage hospitals, users, and system settings.',
};

function StatCard({ label, value, icon, color }) {
  const colors = {
    blue: 'bg-blue-50 text-blue-600 border-blue-100',
    green: 'bg-green-50 text-green-600 border-green-100',
    purple: 'bg-purple-50 text-purple-600 border-purple-100',
    amber: 'bg-amber-50 text-amber-600 border-amber-100',
    red: 'bg-red-50 text-red-600 border-red-100',
  };
  return (
    <div className="card flex items-center gap-4">
      <div className={`w-12 h-12 rounded-xl flex items-center justify-center border ${colors[color] || colors.blue} flex-shrink-0`}>
        {icon}
      </div>
      <div>
        <p className="text-2xl font-bold text-gray-900">{value}</p>
        <p className="text-sm text-gray-500">{label}</p>
      </div>
    </div>
  );
}

function ApiStatusBadge({ status }) {
  if (status === 'checking') {
    return (
      <span className="flex items-center gap-1.5 text-gray-500 text-sm">
        <div className="w-3 h-3 border-2 border-gray-300 border-t-gray-500 rounded-full animate-spin" />
        Checking API...
      </span>
    );
  }
  if (status === 'healthy') {
    return (
      <span className="flex items-center gap-1.5 text-green-600 text-sm font-medium">
        <span className="w-2.5 h-2.5 bg-green-500 rounded-full animate-pulse" />
        API Connected & Healthy
      </span>
    );
  }
  return (
    <span className="flex items-center gap-1.5 text-red-600 text-sm font-medium">
      <span className="w-2.5 h-2.5 bg-red-500 rounded-full" />
      API Unreachable
    </span>
  );
}

function DashboardPage() {
  const { user } = useAuth();
  const [apiStatus, setApiStatus] = useState('checking');
  const [apiData, setApiData] = useState(null);

  // Test the backend API health endpoint on mount
  useEffect(() => {
    const checkApi = async () => {
      try {
        const data = await authService.healthCheck();
        setApiData(data);
        setApiStatus('healthy');
      } catch {
        setApiStatus('error');
      }
    };
    checkApi();
  }, []);

  const roleStats = {
    PATIENT: [
      { label: 'Upcoming Appointments', value: '0', color: 'blue', icon: <CalendarSvg /> },
      { label: 'Medical Reports', value: '0', color: 'green', icon: <FileSvg /> },
      { label: 'Prescriptions', value: '0', color: 'purple', icon: <PillSvg /> },
      { label: 'Doctors Consulted', value: '0', color: 'amber', icon: <UserSvg /> },
    ],
    DOCTOR: [
      { label: "Today's Appointments", value: '0', color: 'blue', icon: <CalendarSvg /> },
      { label: 'Total Patients', value: '0', color: 'green', icon: <UserSvg /> },
      { label: 'Prescriptions Written', value: '0', color: 'purple', icon: <PillSvg /> },
      { label: 'Pending Reviews', value: '0', color: 'amber', icon: <StarSvg /> },
    ],
    HOSPITAL_ADMIN: [
      { label: 'Total Doctors', value: '0', color: 'blue', icon: <UserSvg /> },
      { label: "Today's Appointments", value: '0', color: 'green', icon: <CalendarSvg /> },
      { label: 'Pending Verifications', value: '0', color: 'amber', icon: <CheckSvg /> },
      { label: 'Hospital Rating', value: 'N/A', color: 'purple', icon: <StarSvg /> },
    ],
    SUPER_ADMIN: [
      { label: 'Total Hospitals', value: '0', color: 'blue', icon: <BuildingSvg /> },
      { label: 'Total Doctors', value: '0', color: 'green', icon: <UserSvg /> },
      { label: 'Total Patients', value: '0', color: 'purple', icon: <PatientSvg /> },
      { label: 'Pending Approvals', value: '0', color: 'red', icon: <CheckSvg /> },
    ],
  };

  const stats = roleStats[user?.role] || roleStats.PATIENT;

  return (
    <div className="space-y-6">
      {/* Welcome Banner */}
      <div className="bg-gradient-to-r from-primary-700 to-primary-900 rounded-2xl p-6 text-white">
        <div className="flex items-start justify-between">
          <div>
            <p className="text-primary-200 text-sm font-medium mb-1">
              {new Date().toLocaleDateString('en-IN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
            </p>
            <h1 className="text-2xl font-bold">
              Hello, {user?.full_name?.split(' ')[0]} 👋
            </h1>
            <p className="text-primary-200 text-sm mt-2 max-w-md">
              {ROLE_WELCOME[user?.role]}
            </p>
          </div>
          <div className="hidden sm:flex flex-col items-end gap-2">
            <span className={`text-xs font-semibold px-3 py-1.5 rounded-full
              ${user?.role === 'PATIENT' ? 'bg-blue-500/30 text-blue-200' :
                user?.role === 'DOCTOR' ? 'bg-green-500/30 text-green-200' :
                user?.role === 'HOSPITAL_ADMIN' ? 'bg-purple-500/30 text-purple-200' :
                'bg-red-500/30 text-red-200'}`}>
              {ROLE_LABELS[user?.role]}
            </span>
            {user?.is_verified ? (
              <span className="text-xs flex items-center gap-1 text-green-300">
                <span className="w-2 h-2 bg-green-400 rounded-full" /> Verified
              </span>
            ) : (
              <span className="text-xs flex items-center gap-1 text-amber-300">
                <span className="w-2 h-2 bg-amber-400 rounded-full" /> Pending Verification
              </span>
            )}
          </div>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-4">
        {stats.map((stat) => (
          <StatCard key={stat.label} {...stat} />
        ))}
      </div>

      {/* Two-column section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* API Health Card */}
        <div className="card">
          <div className="flex items-center justify-between mb-4">
            <h2 className="font-semibold text-gray-800">System Status</h2>
            <ApiStatusBadge status={apiStatus} />
          </div>
          {apiData && (
            <div className="space-y-2 text-sm">
              <div className="flex items-center justify-between py-2 border-b border-gray-100">
                <span className="text-gray-500">API Version</span>
                <span className="font-medium text-gray-800">{apiData.version}</span>
              </div>
              <div className="flex items-center justify-between py-2 border-b border-gray-100">
                <span className="text-gray-500">Status</span>
                <span className="font-medium text-green-600 capitalize">{apiData.status}</span>
              </div>
              <div className="flex items-center justify-between py-2">
                <span className="text-gray-500">Backend</span>
                <span className="font-medium text-gray-800">Django + PostgreSQL</span>
              </div>
            </div>
          )}
          {apiStatus === 'error' && (
            <div className="mt-3 p-3 bg-red-50 rounded-lg text-red-600 text-sm">
              Cannot connect to the backend API. Make sure Django server is running on port 8000.
            </div>
          )}
        </div>

        {/* Account Info Card */}
        <div className="card">
          <h2 className="font-semibold text-gray-800 mb-4">Account Details</h2>
          <div className="space-y-2 text-sm">
            <div className="flex items-center justify-between py-2 border-b border-gray-100">
              <span className="text-gray-500">Name</span>
              <span className="font-medium text-gray-800">{user?.full_name}</span>
            </div>
            <div className="flex items-center justify-between py-2 border-b border-gray-100">
              <span className="text-gray-500">Email</span>
              <span className="font-medium text-gray-800">{user?.email}</span>
            </div>
            <div className="flex items-center justify-between py-2 border-b border-gray-100">
              <span className="text-gray-500">Role</span>
              <span className={`font-semibold text-xs px-2.5 py-1 rounded-full
                ${user?.role === 'PATIENT' ? 'bg-blue-100 text-blue-700' :
                  user?.role === 'DOCTOR' ? 'bg-green-100 text-green-700' :
                  user?.role === 'HOSPITAL_ADMIN' ? 'bg-purple-100 text-purple-700' :
                  'bg-red-100 text-red-700'}`}>
                {ROLE_LABELS[user?.role]}
              </span>
            </div>
            <div className="flex items-center justify-between py-2">
              <span className="text-gray-500">Verification</span>
              {user?.is_verified
                ? <span className="text-green-600 font-medium text-xs flex items-center gap-1"><span className="w-2 h-2 bg-green-500 rounded-full" />Verified</span>
                : <span className="text-amber-600 font-medium text-xs flex items-center gap-1"><span className="w-2 h-2 bg-amber-500 rounded-full" />Pending</span>
              }
            </div>
          </div>
        </div>
      </div>

      {/* Quick Actions */}
      <div className="card">
        <h2 className="font-semibold text-gray-800 mb-4">Quick Actions</h2>
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
          {user?.role === 'PATIENT' && (
            <>
              <QuickAction label="Book Appointment" icon={<CalendarSvg />} to="/appointments" color="blue" />
              <QuickAction label="Find a Doctor" icon={<UserSvg />} to="/search" color="green" />
              <QuickAction label="View Records" icon={<FileSvg />} to="/records" color="purple" />
              <QuickAction label="My Profile" icon={<ProfileSvg />} to="/profile" color="amber" />
            </>
          )}
          {user?.role === 'DOCTOR' && (
            <>
              <QuickAction label="View Schedule" icon={<CalendarSvg />} to="/appointments" color="blue" />
              <QuickAction label="My Patients" icon={<UserSvg />} to="/patients" color="green" />
              <QuickAction label="Prescriptions" icon={<PillSvg />} to="/prescriptions" color="purple" />
              <QuickAction label="My Profile" icon={<ProfileSvg />} to="/profile" color="amber" />
            </>
          )}
          {user?.role === 'HOSPITAL_ADMIN' && (
            <>
              <QuickAction label="Manage Hospital" icon={<BuildingSvg />} to="/hospital" color="blue" />
              <QuickAction label="Doctors" icon={<UserSvg />} to="/doctors" color="green" />
              <QuickAction label="Appointments" icon={<CalendarSvg />} to="/appointments" color="purple" />
              <QuickAction label="My Profile" icon={<ProfileSvg />} to="/profile" color="amber" />
            </>
          )}
          {user?.role === 'SUPER_ADMIN' && (
            <>
              <QuickAction label="All Hospitals" icon={<BuildingSvg />} to="/admin/hospitals" color="blue" />
              <QuickAction label="All Users" icon={<UserSvg />} to="/admin/users" color="green" />
              <QuickAction label="Approvals" icon={<CheckSvg />} to="/admin/approvals" color="red" />
              <QuickAction label="My Profile" icon={<ProfileSvg />} to="/profile" color="amber" />
            </>
          )}
        </div>
      </div>
    </div>
  );
}

function QuickAction({ label, icon, to, color }) {
  const colorMap = {
    blue: 'bg-blue-50 hover:bg-blue-100 text-blue-600 border-blue-100',
    green: 'bg-green-50 hover:bg-green-100 text-green-600 border-green-100',
    purple: 'bg-purple-50 hover:bg-purple-100 text-purple-600 border-purple-100',
    amber: 'bg-amber-50 hover:bg-amber-100 text-amber-600 border-amber-100',
    red: 'bg-red-50 hover:bg-red-100 text-red-600 border-red-100',
  };
  return (
    <a href={to} className={`flex flex-col items-center gap-2 p-4 rounded-xl border text-center transition-colors cursor-pointer ${colorMap[color]}`}>
      <div className="w-8 h-8">{icon}</div>
      <span className="text-xs font-medium leading-tight">{label}</span>
    </a>
  );
}

